mapper.select:
select count(*) from dish

    where name like concat('%',#{name},'%')

;

select * from dish

    where name like concat('%',#{name},'%')

order by sort,update_time desc limit #{index},#{pageSize};

select image from dish where id in

    #{id}

;

mapper.delete:
delete from dish where status=0 and id in

    #{id}

;
